sys_script_include.script:
var AN_GradeCalculator =
    Class.create();

AN_GradeCalculator.prototype = {

    calculate: function(scanId) {

        var scorecard =
            new GlideRecord(
                'x_1920012_apprai_0_an_scorecard'
            );

        scorecard.addQuery(
            'scan',
            scanId
        );

        scorecard.query();

        if (!scorecard.next())
            return;

        var security =
            parseInt(
                scorecard.security_score || 0,
                10
            );

        var performance =
            parseInt(
                scorecard.performance_score || 0,
                10
            );

        var quality =
            parseInt(
                scorecard.quality_score || 0,
                10
            );

        var maintainability =
            parseInt(
                scorecard.maintainability_score || 0,
                10
            );

        var updateSet =
            parseInt(
                scorecard.update_set_score || 0,
                10
            );

        var overall =
            (security * 0.35) +
            (performance * 0.25) +
            (quality * 0.20) +
            (maintainability * 0.15) +
            (updateSet * 0.05);

        overall =
            Math.round(overall);

        var grade = 'F';

        if (overall >= 90)
            grade = 'A';
        else if (overall >= 80)
            grade = 'B';
        else if (overall >= 70)
            grade = 'C';
        else if (overall >= 60)
            grade = 'D';

        scorecard.overall_score =
            overall;

        scorecard.grade =
            grade;

        scorecard.update();

        var scanGR =
            new GlideRecord(
                'x_1920012_apprai_0_an_scan'
            );

        if (scanGR.get(scanId)) {

            scanGR.overall_score =
                overall;

            scanGR.overall_grade =
                grade;

            scanGR.status =
                'Completed';

            scanGR.update();
        }
    },

    type:
        'AN_GradeCalculator'
};
